+@page "/catalog"
+@using sv_22ece25b34cf42a58b6e9ba8ac0911f7.Components.Pages.Catalog
+@rendermode InteractiveServer
+@inject IProductService ProductService
+
+<PageTitle>Product Catalog</PageTitle>
+
+<h3 class="mb-4">Product Catalog</h3>
+
+@if (errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @errorMessage
+        <button class="btn btn-link p-0 ms-2" @onclick="RetryAsync">Retry</button>
+    </div>
+}
+else
+{
+    <div class="row">
+        @* Left sidebar — filters *@
+        <div class="col-lg-3 mb-3">
+            <CatalogFilters Categories="@categories"
+                            CurrentFilter="@filter"
+                            OnFilterChanged="HandleFilterChanged" />
+        </div>
+
+        @* Main content area *@
+        <div class="col-lg-9">
+            <CatalogToolbar SortBy="@sortBy"
+                            TotalCount="@totalCount"
+                            Page="@currentPage"
+                            PageSize="@pageSize"
+                            OnSortByChanged="HandleSortChanged" />
+
+            @if (isLoading)
+            {
+                <div class="d-flex justify-content-center py-5">
+                    <div class="spinner-border text-primary" role="status">
+                        <span class="visually-hidden">Loading...</span>
+                    </div>
+                </div>
+            }
+            else if (products.Count == 0)
+            {
+                <div class="text-center py-5 text-muted">
+                    <h5>No products found</h5>
+                    <p>Try adjusting your filters or search criteria.</p>
+                </div>
+            }
+            else
+            {
+                <ProductGrid Products="@products"
+                             OnProductSelected="HandleProductSelected"
+                             OnAddToCart="HandleAddToCart" />
+
+                <CatalogPagination Page="@currentPage"
+                                   TotalCount="@totalCount"
+                                   PageSize="@pageSize"
+                                   OnPageChanged="HandlePageChanged" />
+            }
+        </div>
+    </div>
+}
+
+@code {
+    /// <summary>
+    /// Raised when a product card is clicked so the parent can navigate to a detail page.
+    /// </summary>
+    [Parameter]
+    public EventCallback<Product> OnProductSelected { get; set; }
+
+    private List<Product> products = [];
+    private List<string> categories = [];
+    private ProductFilter filter = new(null, null, null, false);
+    private string sortBy = "price_asc";
+    private int currentPage = 1;
+    private const int pageSize = 12;
+    private int totalCount;
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadDataAsync();
+    }
+
+    private async Task LoadDataAsync()
+    {
+        try
+        {
+            isLoading = true;
+            errorMessage = null;
+
+            var categoriesTask = ProductService.GetCategoriesAsync();
+            var searchTask = ProductService.SearchAsync(filter, sortBy, currentPage, pageSize);
+
+            await Task.WhenAll(categoriesTask, searchTask);
+
+            categories = await categoriesTask;
+            var result = await searchTask;
+            products = result.Items;
+            totalCount = result.TotalCount;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load products. {ex.Message}";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private async Task SearchAsync()
+    {
+        try
+        {
+            isLoading = true;
+            errorMessage = null;
+
+            var result = await ProductService.SearchAsync(filter, sortBy, currentPage, pageSize);
+            products = result.Items;
+            totalCount = result.TotalCount;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load products. {ex.Message}";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private async Task HandleFilterChanged(ProductFilter newFilter)
+    {
+        filter = newFilter;
+        currentPage = 1;
+        await SearchAsync();
+    }
+
+    private async Task HandleSortChanged(string newSort)
+    {
+        sortBy = newSort;
+        currentPage = 1;
+        await SearchAsync();
+    }
+
+    private async Task HandlePageChanged(int page)
+    {
+        currentPage = page;
+        await SearchAsync();
+    }
+
+    private async Task HandleProductSelected(Product product)
+    {
+        await OnProductSelected.InvokeAsync(product);
+    }
+
+    private async Task HandleAddToCart(Product product)
+    {
+        // Placeholder — wire up to a cart service when available
+    }
+
+    private async Task RetryAsync()
+    {
+        await LoadDataAsync();
+    }
+}
+

